  <!-- wp:paragraph {"style":{"typography":{"fontSize":"1.1rem","lineHeight":"1.7"}}} -->
  <p style="font-size:1.1rem;line-height:1.7">DJ Franco is a Tampa-based open-format DJ with a reputation for delivering polished, high-energy performances and a global influence to every stage he touches. With over ten years of professional experience, his career spans Florida and beyond — with performances in Atlanta, Louisiana, Mexico and more.</p>
  <!-- /wp:paragraph -->

  <!-- wp:pullquote {"style":{"typography":{"fontFamily":"var(--wp--preset--font-family--display)","fontSize":"var(--wp--preset--font-size--2xl)","textTransform":"uppercase","lineHeight":"1.05"}}} -->
